public int longestSubsequence(int[] nums, int k) {
    int n = nums.length;
    TreeMap<Integer, Integer> dp = new TreeMap<>();
    int ans = 0;

    for (int num : nums) {
        int temp = 0;
        Integer key = dp.lowerKey(num - k);
        if (key != null) {
            temp = dp.get(key);
        }
        dp.put(num, Math.max(dp.getOrDefault(num, 0), temp + 1));
        ans = Math.max(ans, dp.get(num));
    }

    return ans;
}
```

